// Plugin registry.
//
// Convention enforced here: register(h) throws unless h.name is kebab-case
// (/^[a-z]+(-[a-z]+)*$/) and typeof h.handle === 'function'. all() returns the
// registered handlers in registration order.
const NAME_RE = /^[a-z]+(-[a-z]+)*$/;
const handlers = [];
function register(h) {
  if (!h || !NAME_RE.test(h.name) || typeof h.handle !== "function") {
    throw new Error(`invalid handler: ${h && h.name}`);
  }
  handlers.push(h);
  return h;
}
function all() {
  return handlers;
}
module.exports = { register, all };
